    s = stdin.readline().strip()
    print(Solution().remove_duplicates(s))

solutions.cpp:
class Solution {
public:
    static string removeDuplicates(string s) {
        string result = "";
        for(char c : s) {
            if(result.empty() || c != result.back())
                result += c;
        }
        return result;
    }
};
int main() {
    string s;
    cin >> s;
    cout << Solution::removeDuplicates(s) << endl;
    return 0;
}
